import{_ as e,o as n,c as s,ag as a}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"数制与数据容量计算复习","description":"","frontmatter":{"title":"数制与数据容量计算复习"},"headers":[],"relativePath":"high-school-it/knowledge-2.md","filePath":"high-school-it/knowledge-2.md"}'),l={name:"high-school-it/knowledge-2.md"};function i(r,t,d,p,g,o){return n(),s("div",null,[...t[0]||(t[0]=[a(`<h1 id="知识点2-数制与数据容量计算复习" tabindex="-1">知识点2： 数制与数据容量计算复习 <a class="header-anchor" href="#知识点2-数制与数据容量计算复习" aria-label="Permalink to &quot;知识点2： 数制与数据容量计算复习&quot;">​</a></h1><h2 id="一、进制转换" tabindex="-1">一、进制转换 <a class="header-anchor" href="#一、进制转换" aria-label="Permalink to &quot;一、进制转换&quot;">​</a></h2><h3 id="常用对应表" tabindex="-1">常用对应表 <a class="header-anchor" href="#常用对应表" aria-label="Permalink to &quot;常用对应表&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">十进制</th><th style="text-align:center;">0</th><th style="text-align:center;">1</th><th style="text-align:center;">2</th><th style="text-align:center;">3</th><th style="text-align:center;">4</th><th style="text-align:center;">5</th><th style="text-align:center;">6</th><th style="text-align:center;">7</th><th style="text-align:center;">8</th><th style="text-align:center;">9</th><th style="text-align:center;">10</th><th style="text-align:center;">11</th><th style="text-align:center;">12</th><th style="text-align:center;">13</th><th style="text-align:center;">14</th><th style="text-align:center;">15</th></tr></thead><tbody><tr><td style="text-align:center;">二进制</td><td style="text-align:center;">0000</td><td style="text-align:center;">0001</td><td style="text-align:center;">0010</td><td style="text-align:center;">0011</td><td style="text-align:center;">0100</td><td style="text-align:center;">0101</td><td style="text-align:center;">0110</td><td style="text-align:center;">0111</td><td style="text-align:center;">1000</td><td style="text-align:center;">1001</td><td style="text-align:center;">1010</td><td style="text-align:center;">1011</td><td style="text-align:center;">1100</td><td style="text-align:center;">1101</td><td style="text-align:center;">1110</td><td style="text-align:center;">1111</td></tr><tr><td style="text-align:center;">十六进制</td><td style="text-align:center;">0</td><td style="text-align:center;">1</td><td style="text-align:center;">2</td><td style="text-align:center;">3</td><td style="text-align:center;">4</td><td style="text-align:center;">5</td><td style="text-align:center;">6</td><td style="text-align:center;">7</td><td style="text-align:center;">8</td><td style="text-align:center;">9</td><td style="text-align:center;">A</td><td style="text-align:center;">B</td><td style="text-align:center;">C</td><td style="text-align:center;">D</td><td style="text-align:center;">E</td><td style="text-align:center;">F</td></tr></tbody></table><h3 id="十进制-↔-二进制" tabindex="-1">十进制 ↔ 二进制 <a class="header-anchor" href="#十进制-↔-二进制" aria-label="Permalink to &quot;十进制 ↔ 二进制&quot;">​</a></h3><h4 id="十进制-→-二进制-除2取余法" tabindex="-1">十进制 → 二进制（除2取余法） <a class="header-anchor" href="#十进制-→-二进制-除2取余法" aria-label="Permalink to &quot;十进制 → 二进制（除2取余法）&quot;">​</a></h4><p>不断除以2，记录余数，<strong>从下往上</strong>读余数</p><p><strong>例</strong>：25(10) = ?</p><table tabindex="0"><thead><tr><th style="text-align:center;">运算</th><th style="text-align:center;">余数</th></tr></thead><tbody><tr><td style="text-align:center;">25 ÷ 2 = 12</td><td style="text-align:center;"><strong>1</strong></td></tr><tr><td style="text-align:center;">12 ÷ 2 = 6</td><td style="text-align:center;"><strong>0</strong></td></tr><tr><td style="text-align:center;">6 ÷ 2 = 3</td><td style="text-align:center;"><strong>0</strong></td></tr><tr><td style="text-align:center;">3 ÷ 2 = 1</td><td style="text-align:center;"><strong>1</strong></td></tr><tr><td style="text-align:center;">1 ÷ 2 = 0</td><td style="text-align:center;"><strong>1</strong></td></tr></tbody></table><p>从下往上读余数：<strong>1 1 0 0 1</strong></p><p><strong>结果</strong>：25(10) = <strong>11001</strong>(2)</p><hr><h4 id="二进制-→-十进制-按权展开求和法" tabindex="-1">二进制 → 十进制（按权展开求和法） <a class="header-anchor" href="#二进制-→-十进制-按权展开求和法" aria-label="Permalink to &quot;二进制 → 十进制（按权展开求和法）&quot;">​</a></h4><p>每位 × 2的对应次方，然后相加</p><p><strong>例</strong>：1011(2) = ?</p><table tabindex="0"><thead><tr><th style="text-align:center;">位置</th><th style="text-align:center;">3</th><th style="text-align:center;">2</th><th style="text-align:center;">1</th><th style="text-align:center;">0</th></tr></thead><tbody><tr><td style="text-align:center;">二进制位</td><td style="text-align:center;">1</td><td style="text-align:center;">0</td><td style="text-align:center;">1</td><td style="text-align:center;">1</td></tr><tr><td style="text-align:center;">权值</td><td style="text-align:center;">2³</td><td style="text-align:center;">2²</td><td style="text-align:center;">2¹</td><td style="text-align:center;">2⁰</td></tr><tr><td style="text-align:center;">位值</td><td style="text-align:center;">1×8</td><td style="text-align:center;">0×4</td><td style="text-align:center;">1×2</td><td style="text-align:center;">1×1</td></tr><tr><td style="text-align:center;">结果</td><td style="text-align:center;">8</td><td style="text-align:center;">0</td><td style="text-align:center;">2</td><td style="text-align:center;">1</td></tr></tbody></table><p>8 + 0 + 2 + 1 = <strong>11</strong></p><p><strong>结果</strong>：1011(2) = <strong>11</strong>(10)</p><hr><h3 id="二进制-↔-十六进制" tabindex="-1">二进制 ↔ 十六进制 <a class="header-anchor" href="#二进制-↔-十六进制" aria-label="Permalink to &quot;二进制 ↔ 十六进制&quot;">​</a></h3><h4 id="二进制-→-十六进制-四位一组" tabindex="-1">二进制 → 十六进制（四位一组） <a class="header-anchor" href="#二进制-→-十六进制-四位一组" aria-label="Permalink to &quot;二进制 → 十六进制（四位一组）&quot;">​</a></h4><p>每4位二进制对应1位十六进制，从右往左分组</p><p><strong>例</strong>：10111110(2) = ?</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>分组（从右往左，每4位一组）：</span></span>
<span class="line"><span>  1011  1110</span></span>
<span class="line"><span>    ↓     ↓</span></span>
<span class="line"><span>    B     E</span></span></code></pre></div><p><strong>结果</strong>：10111110(2) = <strong>BE</strong>(16)</p><hr><h4 id="十六进制-→-二进制" tabindex="-1">十六进制 → 二进制 <a class="header-anchor" href="#十六进制-→-二进制" aria-label="Permalink to &quot;十六进制 → 二进制&quot;">​</a></h4><p>每1位十六进制对应4位二进制</p><p><strong>例</strong>：A5(16) = ?</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  A    5</span></span>
<span class="line"><span>  ↓    ↓</span></span>
<span class="line"><span>1010 0101</span></span></code></pre></div><p><strong>结果</strong>：A5(16) = <strong>10100101</strong>(2)</p><hr><h4 id="十进制-→-十六进制" tabindex="-1">十进制 → 十六进制 <a class="header-anchor" href="#十进制-→-十六进制" aria-label="Permalink to &quot;十进制 → 十六进制&quot;">​</a></h4><p><strong>方法1</strong>：先转二进制，再四位分组</p><p><strong>例</strong>：255(10) = ?</p><p><strong>Step 1</strong>：转二进制</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>255 ÷ 2 = 127 ... 1</span></span>
<span class="line"><span>127 ÷ 2 = 63  ... 1</span></span>
<span class="line"><span>63 ÷ 2  = 31  ... 1</span></span>
<span class="line"><span>31 ÷ 2  = 15  ... 1</span></span>
<span class="line"><span>15 ÷ 2  = 7   ... 1</span></span>
<span class="line"><span>7 ÷ 2   = 3   ... 1</span></span>
<span class="line"><span>3 ÷ 2   = 1   ... 1</span></span>
<span class="line"><span>1 ÷ 2   = 0   ... 1</span></span></code></pre></div><p>255(10) = 11111111(2)</p><p><strong>Step 2</strong>：四位分组</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  1111  1111</span></span>
<span class="line"><span>    ↓     ↓</span></span>
<span class="line"><span>    F     F</span></span></code></pre></div><p><strong>结果</strong>：255(10) = <strong>FF</strong>(16)</p><p><strong>方法2</strong>：除16取余法</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>255 ÷ 16 = 15 ... 15(F)</span></span>
<span class="line"><span> 15 ÷ 16 =  0 ... 15(F)</span></span></code></pre></div><p>从下往上读：F F</p><p><strong>结果</strong>：255(10) = <strong>FF</strong>(16)</p><hr><h2 id="二、图片与声音的数据量计算" tabindex="-1">二、图片与声音的数据量计算 <a class="header-anchor" href="#二、图片与声音的数据量计算" aria-label="Permalink to &quot;二、图片与声音的数据量计算&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">图片数据量（位图）</p><p><strong>公式</strong>：数据量 = 宽 × 高 × 色彩深度(bit)</p><p>色彩深度决定颜色数：</p><ul><li>1 bit → 2色（黑白）</li><li>8 bit → 256色</li><li>16 bit → 65536色</li><li>24 bit → 1677万色（真彩色）</li></ul><p><strong>注意</strong>：结果单位是 bit，换算 ÷8 = Byte</p></div><div class="tip custom-block"><p class="custom-block-title">声音数据量（PCM 数字音频）</p><p><strong>公式</strong>：数据量 = 采样频率 × 量化位数 × 声道数 × 时长</p><ul><li>采样频率：每秒采样次数（Hz/kHz）</li><li>量化位数：每次采样用多少 bit 记录</li><li>声道数：单声道1，立体声2</li><li>时长：单位为秒</li></ul><p><strong>注意</strong>：结果单位是 bit，÷8 = Byte</p></div><div class="warning custom-block"><p class="custom-block-title">单位换算（必须熟记）</p><ul><li>1 Byte = 8 bit</li><li>1 KB = 1024 B</li><li>1 MB = 1024 KB</li><li>1 GB = 1024 MB</li></ul><p><strong>注意区分</strong>：存储用1024进位</p></div><hr><h2 id="三、传输时间计算" tabindex="-1">三、传输时间计算 <a class="header-anchor" href="#三、传输时间计算" aria-label="Permalink to &quot;三、传输时间计算&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">核心公式</p><p><strong>传输时间（秒） = 数据量（bit） ÷ 传输速率（bps）</strong></p><p>bps = bit per second（位/秒），两者是同一单位</p><p>常见速率单位：</p><ul><li>bps（或 bit/s）= 位/秒</li><li>Kbps = 1024 bps</li><li>Mbps = 1024 Kbps</li><li>Gbps = 1024 Mbps</li></ul><p><strong>注意</strong>：K 通常指 <strong>1024</strong></p><p><strong>易错点</strong>：数据量单位是 Byte（字节），速率单位是 bit（位），必须先将数据量乘以8转换为 bit，再做除法</p></div><div class="tip custom-block"><p class="custom-block-title">解题步骤</p><ol><li>计算数据量，统一换算为 <strong>bit</strong></li><li>将传输速率统一为 <strong>bps</strong>（如 10 Mbps = 10×1024×1024 bps）</li><li>时间 = 数据量(bit) ÷ 速率(bps)，结果单位为 <strong>秒</strong></li><li>如需换算分钟：÷60；换算小时：÷3600</li></ol></div><hr><h2 id="四、练习题目" tabindex="-1">四、练习题目 <a class="header-anchor" href="#四、练习题目" aria-label="Permalink to &quot;四、练习题目&quot;">​</a></h2><h3 id="a-组-—-进制转换" tabindex="-1">A 组 — 进制转换 <a class="header-anchor" href="#a-组-—-进制转换" aria-label="Permalink to &quot;A 组 — 进制转换&quot;">​</a></h3><details><summary>第 1 题（基础）— 将十进制数 45 转换为二进制数</summary><table tabindex="0"><thead><tr><th style="text-align:center;">运算</th><th style="text-align:center;">余数</th></tr></thead><tbody><tr><td style="text-align:center;">45 ÷ 2 = 22</td><td style="text-align:center;"><strong>1</strong></td></tr><tr><td style="text-align:center;">22 ÷ 2 = 11</td><td style="text-align:center;"><strong>0</strong></td></tr><tr><td style="text-align:center;">11 ÷ 2 = 5</td><td style="text-align:center;"><strong>1</strong></td></tr><tr><td style="text-align:center;">5 ÷ 2 = 2</td><td style="text-align:center;"><strong>1</strong></td></tr><tr><td style="text-align:center;">2 ÷ 2 = 1</td><td style="text-align:center;"><strong>0</strong></td></tr><tr><td style="text-align:center;">1 ÷ 2 = 0</td><td style="text-align:center;"><strong>1</strong></td></tr></tbody></table><p>从下往上读余数：<strong>1 0 1 1 0 1</strong></p><p><strong>结果</strong>：45(10) = <strong>101101</strong>(2)</p></details><details><summary>第 2 题（基础）— 将二进制数 10110011 转换为十进制数</summary><table tabindex="0"><thead><tr><th style="text-align:center;">位置</th><th style="text-align:center;">7</th><th style="text-align:center;">6</th><th style="text-align:center;">5</th><th style="text-align:center;">4</th><th style="text-align:center;">3</th><th style="text-align:center;">2</th><th style="text-align:center;">1</th><th style="text-align:center;">0</th></tr></thead><tbody><tr><td style="text-align:center;">二进制位</td><td style="text-align:center;">1</td><td style="text-align:center;">0</td><td style="text-align:center;">1</td><td style="text-align:center;">1</td><td style="text-align:center;">0</td><td style="text-align:center;">0</td><td style="text-align:center;">1</td><td style="text-align:center;">1</td></tr><tr><td style="text-align:center;">权值</td><td style="text-align:center;">2⁷</td><td style="text-align:center;">2⁶</td><td style="text-align:center;">2⁵</td><td style="text-align:center;">2⁴</td><td style="text-align:center;">2³</td><td style="text-align:center;">2²</td><td style="text-align:center;">2¹</td><td style="text-align:center;">2⁰</td></tr><tr><td style="text-align:center;">位值</td><td style="text-align:center;">128</td><td style="text-align:center;">0</td><td style="text-align:center;">32</td><td style="text-align:center;">16</td><td style="text-align:center;">0</td><td style="text-align:center;">0</td><td style="text-align:center;">2</td><td style="text-align:center;">1</td></tr></tbody></table><p>128 + 0 + 32 + 16 + 0 + 0 + 2 + 1 = <strong>179</strong></p><p><strong>结果</strong>：10110011(2) = <strong>179</strong>(10)</p></details><details><summary>第 3 题（基础）— 将十六进制数 3F 转换为十进制数</summary><table tabindex="0"><thead><tr><th style="text-align:center;">位</th><th style="text-align:center;">权值</th><th style="text-align:left;">计算</th></tr></thead><tbody><tr><td style="text-align:center;">3</td><td style="text-align:center;">16¹</td><td style="text-align:left;">3 × 16 = 48</td></tr><tr><td style="text-align:center;">F</td><td style="text-align:center;">16⁰</td><td style="text-align:left;">15 × 1 = 15</td></tr></tbody></table><p>48 + 15 = <strong>63</strong></p><p><strong>结果</strong>：3F(16) = <strong>63</strong>(10)</p></details><details><summary>第 4 题（进阶）— 将十六进制数 B7 转换为二进制数</summary><table tabindex="0"><thead><tr><th style="text-align:center;">十六进制位</th><th style="text-align:center;">转二进制</th></tr></thead><tbody><tr><td style="text-align:center;">B (11)</td><td style="text-align:center;">1011</td></tr><tr><td style="text-align:center;">7</td><td style="text-align:center;">0111</td></tr></tbody></table><p>直接拼接：<strong>10110111</strong></p><p><strong>结果</strong>：B7(16) = <strong>10110111</strong>(2)</p></details><details><summary>第 5 题（进阶）— 将二进制数 110101001 转换为十六进制数</summary><p>从右向左每4位一组（不足4位左边补0）：</p><table tabindex="0"><thead><tr><th style="text-align:center;">分组</th><th style="text-align:center;">0001</th><th style="text-align:center;">1010</th><th style="text-align:center;">1001</th></tr></thead><tbody><tr><td style="text-align:center;">对应值</td><td style="text-align:center;">1</td><td style="text-align:center;">A</td><td style="text-align:center;">9</td></tr></tbody></table><p><strong>结果</strong>：110101001(2) = <strong>1A9</strong>(16)</p></details><details><summary>第 6 题（进阶）— 将十进制数 200 转换为十六进制数</summary><table tabindex="0"><thead><tr><th style="text-align:center;">运算</th><th style="text-align:center;">余数</th></tr></thead><tbody><tr><td style="text-align:center;">200 ÷ 16 = 12</td><td style="text-align:center;"><strong>8</strong></td></tr><tr><td style="text-align:center;">12 ÷ 16 = 0</td><td style="text-align:center;"><strong>12(C)</strong></td></tr></tbody></table><p>从下往上读：12(C) 8 → <strong>C8</strong></p><p><strong>结果</strong>：200(10) = <strong>C8</strong>(16)</p></details><hr><h3 id="b-组-—-图片-声音数据量" tabindex="-1">B 组 — 图片 / 声音数据量 <a class="header-anchor" href="#b-组-—-图片-声音数据量" aria-label="Permalink to &quot;B 组 — 图片 / 声音数据量&quot;">​</a></h3><details><summary>第 7 题（基础）— 一张 1920×1080、24bit 的图片，数据量是多少 MB？</summary><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>数据量(bit) = 1920 × 1080 × 24 = 49,766,400 bit</span></span>
<span class="line"><span>÷ 8        = 6,220,800 Byte</span></span>
<span class="line"><span>÷ 1024     = 6075 KB</span></span>
<span class="line"><span>÷ 1024     ≈ 5.93 MB</span></span></code></pre></div><p><strong>答案</strong>：约 <strong>5.93 MB</strong></p></details><details><summary>第 8 题（基础）— 3分钟立体声音频（44100Hz/16bit），数据量是多少 MB？</summary><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>时长 = 3 × 60 = 180 秒</span></span>
<span class="line"><span>数据量(bit) = 44100 × 16 × 2 × 180 = 254,016,000 bit</span></span>
<span class="line"><span>÷ 8        = 31,752,000 Byte</span></span>
<span class="line"><span>÷ 1024     ≈ 31007.8 KB</span></span>
<span class="line"><span>÷ 1024     ≈ 30.28 MB</span></span></code></pre></div><p><strong>答案</strong>：约 <strong>30.28 MB</strong></p></details><details><summary>第 9 题（进阶）— 4K视频（3840×2160/30fps/24bit）1分钟数据量是多少 GB？</summary><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>单帧数据量(bit) = 3840 × 2160 × 24 = 199,065,600 bit</span></span>
<span class="line"><span>总帧数          = 30 × 60 = 1800 帧</span></span>
<span class="line"><span>总数据量(bit)   = 199,065,600 × 1800 = 358,318,080,000 bit</span></span>
<span class="line"><span>÷ 8             = 44,789,760,000 Byte</span></span>
<span class="line"><span>÷ 1024³         ≈ 41.70 GB</span></span></code></pre></div><p><strong>答案</strong>：约 <strong>41.70 GB</strong></p></details><hr><h3 id="c-组-—-传输时间计算" tabindex="-1">C 组 — 传输时间计算 <a class="header-anchor" href="#c-组-—-传输时间计算" aria-label="Permalink to &quot;C 组 — 传输时间计算&quot;">​</a></h3><details><summary>第 10 题（基础）— 50MB 文件，10Mbps 网络下载，需要多少秒？</summary><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>数据量 = 50 MB = 50 × 1024 × 1024 × 8 bit = 419,430,400 bit</span></span>
<span class="line"><span>速率   = 10 Mbps = 10 × 1024 × 1024 bps</span></span>
<span class="line"><span>时间   = 419,430,400 ÷ 10,485,760 ≈ 41.94 秒</span></span></code></pre></div><p><strong>答案</strong>：约 <strong>41.94 秒</strong></p></details><details><summary>第 11 题（进阶）— 4.7GB 影片，100Mbps 网速，需要多少分钟？</summary><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>数据量 = 4.7 × 1024³ × 8 bit ≈ 40,367,734,784 bit</span></span>
<span class="line"><span>速率   = 100 × 1024² = 104,857,600 bps</span></span>
<span class="line"><span>时间   = 40,367,734,784 ÷ 104,857,600 ≈ 385.0 秒</span></span>
<span class="line"><span>÷ 60   ≈ 6.4 分钟</span></span></code></pre></div><p><strong>答案</strong>：约 <strong>6.4 分钟</strong></p></details><details><summary>第 12 题（综合）— 800×600/24bit 图片，512Kbps 网络传输，需要多少秒？</summary><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>数据量 = 800 × 600 × 24 = 11,520,000 bit</span></span>
<span class="line"><span>速率   = 512 × 1024 = 524,288 bps</span></span>
<span class="line"><span>时间   = 11,520,000 ÷ 524,288 ≈ 21.97 秒 ≈ 22 秒</span></span></code></pre></div><p><strong>答案</strong>：约 <strong>22 秒</strong></p><p><strong>注意</strong>：网络速率中 1K=1024</p></details><details><summary>第 13 题（综合）— 5分钟单声道语音（8000Hz/8bit），256Kbps 上传，需要多少分钟？</summary><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>时长   = 5 × 60 = 300 秒</span></span>
<span class="line"><span>数据量 = 8000 × 8 × 1 × 300 = 19,200,000 bit</span></span>
<span class="line"><span>速率   = 256 × 1024 = 262,144 bps</span></span>
<span class="line"><span>时间   = 19,200,000 ÷ 262,144 ≈ 73.24 秒</span></span>
<span class="line"><span>÷ 60   ≈ 1.22 分钟</span></span></code></pre></div><p><strong>答案</strong>：约 <strong>1.22 分钟（1分13秒）</strong></p></details><h2 id="五、真题" tabindex="-1">五、真题 <a class="header-anchor" href="#五、真题" aria-label="Permalink to &quot;五、真题&quot;">​</a></h2><p><strong>13.（2025-01，综合题一）</strong> 如果绘制人脸位置的矩形框边框的RGB值为(255,0,0)，则绘制出来为红色。该颜色值中&quot;255&quot;转换为十六进制数应是（ ）</p><ul><li>A. FE</li><li>B. EE</li><li>C. FF</li><li>D. EF</li></ul><p><strong>14.（2025-03，综合题一）</strong> 某像素点的颜色值使用十六进制表示为(FF,00,00)，则其灰度值Gray用十进制表示是（ ）（GARY = （R + G + B） /3）</p><h3 id="答案" tabindex="-1">答案 <a class="header-anchor" href="#答案" aria-label="Permalink to &quot;答案&quot;">​</a></h3><p>C. FF</p><p>A. 85</p>`,81)])])}const y=e(l,[["render",i]]);export{h as __pageData,y as default};
